INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Universal capture$q$, $q$Save typed notes, handwritten scans, PDFs, images, audio recordings, and full web pages into a single searchable archive.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Web Clipper$q$, $q$A browser extension that saves full articles, simplified text, screenshots, or bookmarks directly from Chrome, Firefox, Safari, and Edge.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Document and handwriting OCR$q$, $q$Automatically recognizes and indexes printed and handwritten text inside photographed or scanned documents so it becomes searchable.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$AI Assistant and semantic search$q$, $q$AI-powered search and summarization tools available on paid tiers that understand meaning and context, not just exact keyword matches.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Notebooks, tags, and Spaces$q$, $q$Multiple layers of organization — notebooks for filing, tags for cross-cutting labels, and Spaces for grouping related notebooks and notes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Tasks and calendar$q$, $q$Built-in task management with due dates and reminders, plus calendar integration to view notes alongside scheduled events.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Cross-device sync$q$, $q$Native apps for Windows, macOS, iOS, and Android plus a web client, with sync limited by device count on lower tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Enterprise administration$q$, $q$SSO, centralized user administration, activity logging, and a dedicated customer success manager on the Enterprise tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Deep, mature OCR and document/handwriting search built up over more than a decade$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Very high brand recognition and a huge installed base of existing users and note archives$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Broad platform coverage across Windows, macOS, iOS, Android, and web$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Recently added AI features (AI Assistant, semantic search, transcription) narrow the gap with newer AI-native note apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Free plan is heavily capped (50 notes, 1 device sync, 1GB storage), pushing most regular users toward a paid tier quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Historically inconsistent sync reliability, a long-running user complaint predating the Bending Spoons acquisition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Pricing is noticeably higher than several modern competitors like Notion's free/personal tiers or Apple Notes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$2023 restructuring and relocation of operations to Europe caused uncertainty and support disruption for some long-time users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Who owns Evernote now?$q$, $q$Evernote is owned by Bending Spoons, an Italian technology company headquartered in Milan that acquired Evernote Corporation in a deal announced in November 2022 and closed in January 2023.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Is Evernote free to use?$q$, $q$Yes, Evernote offers a Free plan, but it is capped at 50 notes, 1 notebook, sync on a single device, and 1GB of monthly upload storage. Most regular users need a paid Starter or Advanced plan for practical daily use.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$What is the difference between Evernote Starter and Advanced?$q$, $q$Starter raises limits to 1,000 notes, 20 notebooks, and 3-device sync with 5GB storage. Advanced removes all numeric caps entirely and unlocks the full AI feature set, including the AI Assistant, semantic search, AI transcription, and AI edit.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Does Evernote have AI features?$q$, $q$Yes. Since its relaunch under Bending Spoons, Evernote has added an AI Assistant, semantic (meaning-based) search, AI transcription for handwritten and audio notes, and AI-assisted editing, available on the Advanced and Enterprise tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$What happened to Evernote after the Bending Spoons acquisition?$q$, $q$In July 2023, Evernote moved its center of operations from the United States to Europe to align with parent company Bending Spoons in Milan, which involved layoffs of much of its previous US-based staff and a rebuild of its backend infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$What are the best alternatives to Evernote?$q$, $q$Common alternatives include Notion for teams wanting databases and wikis alongside notes, Microsoft OneNote for organizations standardized on Microsoft 365, Apple Notes and Google Keep for lightweight casual capture, and Obsidian or Craft for users who prefer local-first, networked note-taking.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Personal knowledge archive$q$, $q$Individuals capture research, articles, receipts, and meeting notes into one searchable repository they can retrieve years later using OCR-powered search.$q$, $q$Individual professionals and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Academic note-taking$q$, $q$Students photograph handwritten notes and whiteboards, clip web articles for research, and organize coursework by notebook and tag ahead of exams.$q$, $q$Students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Lightweight team documentation$q$, $q$Small teams use shared notebooks and Spaces to keep meeting notes, project references, and onboarding material in one place without adopting a full project-management suite.$q$, $q$Small teams and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["50 notes, 1 notebook, 5 Spaces, 20 tags","Sync on 1 device","1GB monthly upload storage","Web Clipper and basic apps across platforms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Starter$q$, $q$$14.99/month ($10.83/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1,000 notes, 20 notebooks, 10 Spaces, 100 tags","Sync on 3 devices","5GB monthly upload storage, 200 attachments","Tasks and calendar integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Advanced$q$, $q$$24/month ($20.83/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited notes, notebooks, Spaces, and tags","Unlimited device sync, storage, and attachments","Full AI feature set: AI Assistant, semantic search, AI transcribe, AI edit"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Enterprise$q$, $q$Custom$q$, $q$annual (quote-based)$q$, NULL, $q$["Custom limits","SSO and centralized administration","Dedicated customer success manager","Priority support and user activity logging"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Evernote is a note-taking and personal knowledge management application that lets users capture typed notes, web clippings, scanned documents, photos, and audio, then organize and retrieve them through notebooks, tags, and full-text and AI-assisted semantic search.$q$, $q$Originally launched in 2008 and now owned by Italian technology company Bending Spoons following a January 2023 acquisition, Evernote has been rebuilt with modern infrastructure and a new set of AI features aimed at competing with newer note-taking and second-brain tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Evernote's signature capability is capturing information in almost any format — typed text, handwriting, web pages, PDFs, images, and voice memos — and making all of it searchable, including handwritten and printed text inside photos via optical character recognition.$q$, $q$On its higher tiers, Evernote layers AI on top of this archive: an AI Assistant that can summarize and answer questions about your notes, semantic search that understands meaning rather than exact keywords, AI transcription for handwritten and spoken notes, and AI-assisted editing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Evernote uses a four-tier freemium model: a capped Free plan, a Starter plan for individuals who need more storage and devices, an Advanced plan that removes all caps and unlocks full AI features, and a custom-quoted Enterprise plan with administration and security controls for teams.$q$, $q$Starter runs about $14.99 per month billed monthly or roughly $10.83 per month billed annually, while Advanced runs about $24 per month billed monthly or roughly $20.83 per month billed annually; Enterprise pricing is quote-based.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
