INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$TypeScript and Node.js core$q$, $q$The entire platform, backend and frontend, is written in TypeScript on Node.js, matching modern JavaScript engineering stacks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$GraphQL API$q$, $q$A GraphQL layer exposes products, carts, orders, and customer data, enabling headless integrations and custom storefronts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Modular extension system$q$, $q$Payment gateways, shipping rules, tax logic, and catalog behavior can be added as isolated modules without modifying core code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$React-based admin panel$q$, $q$A customizable admin dashboard for managing catalog, orders, customers, and store configuration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Self-hosted deployment$q$, $q$Runs on standard Node.js hosting or Docker, giving teams full control over infrastructure, data residency, and scaling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Customizable storefront theme$q$, $q$The default storefront is a replaceable React theme, allowing full visual and functional customization of the shopping experience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$PostgreSQL data layer$q$, $q$Uses PostgreSQL as its relational database, a familiar and well-supported choice for engineering teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Open source license$q$, $q$Source code is publicly available on GitHub, allowing inspection, self-hosting, and community contribution at no cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Free and unlimited for self-hosted deployments with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Modern, type-safe JavaScript/TypeScript stack that matches many engineering teams' existing tooling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Modular architecture keeps the core upgradeable without heavy custom-code merge conflicts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Full control over data, infrastructure, and storefront customization$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Requires development resources to install, host, and maintain; not suited to non-technical merchants$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Smaller plugin/extension ecosystem and community than more established competitors like Medusa.js or WooCommerce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Managed cloud hosting tiers were still listed as 'not yet available' at time of research, limiting turnkey hosting options$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Less enterprise track record and fewer public case studies than legacy commerce platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Is EverShop free to use?$q$, $q$Yes. EverShop is open source and free to self-host with no license fees or feature restrictions. The project has also announced optional paid managed cloud plans for teams that don't want to operate their own servers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$What technology stack does EverShop use?$q$, $q$EverShop is built with Node.js and TypeScript on the backend, React for both the storefront and admin panel, GraphQL as the API layer, and PostgreSQL as the database.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Is EverShop suitable for non-technical merchants?$q$, $q$Not really. EverShop is designed for developers and technical teams who want to self-host and customize their store at the code level. Non-technical merchants are generally better served by hosted platforms like Shopify.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$How does EverShop compare to Medusa.js?$q$, $q$Both are open source, Node.js-based, headless-capable commerce platforms aimed at developers. Medusa.js has a larger community, more integrations, and venture backing, while EverShop emphasizes a leaner, TypeScript-native core.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Can EverShop be used headlessly?$q$, $q$Yes. Because commerce data is exposed through a GraphQL API, teams can build a fully custom or headless frontend against EverShop instead of using its default React storefront theme.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Does EverShop offer managed hosting?$q$, $q$EverShop has announced Personal and Professional managed cloud plans at roughly $10 and $20 per month respectively, layering managed hosting, SSL, and storage on top of the open source engine.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Custom developer-built storefronts$q$, $q$Engineering teams use EverShop's GraphQL API and modular architecture to build a fully bespoke shopping experience rather than customizing a no-code template.$q$, $q$Software engineers and technical founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Agency-built ecommerce projects$q$, $q$Digital agencies self-host EverShop for clients who need a modern, maintainable open source store without recurring SaaS platform fees.$q$, $q$Digital agencies and freelance developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Headless commerce integrations$q$, $q$Teams already running a separate frontend framework connect it to EverShop's GraphQL backend to power product, cart, and checkout functionality headlessly.$q$, $q$Headless commerce and composable architecture teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited products and orders","Full source code access on GitHub","Fully customizable storefront and admin panel","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Personal (Cloud)$q$, $q$$10/month$q$, $q$monthly (20% discount annually)$q$, NULL, $q$["Managed hosting","Free SSL certificate","S3-backed storage","Basic configuration support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$Professional (Cloud)$q$, $q$$20/month$q$, $q$monthly (20% discount annually)$q$, NULL, $q$["Managed hosting","Free SSL certificate","S3-backed storage","Deploy-from-GitHub integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EverShop is an open source ecommerce platform built on Node.js, TypeScript, React, and GraphQL, designed for developers who want to self-host a fully customizable online store rather than use a hosted, no-code storefront builder.$q$, $q$Its modular architecture separates the GraphQL API, the customizable React storefront, and the React-based admin panel, letting technical teams extend or replace core commerce functionality without forking the codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$EverShop ships with core commerce essentials — product catalog, cart and checkout, order management, and an admin dashboard — implemented as first-party modules on top of a PostgreSQL database and a GraphQL API layer.$q$, $q$Because the frontend and backend are decoupled through GraphQL, teams can build a fully custom storefront or integrate EverShop headlessly into an existing frontend, while still relying on the built-in React admin panel for operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core EverShop platform is free and open source for self-hosting, with no license fees or feature gating for teams that run their own infrastructure.$q$, $q$EverShop has also announced managed cloud tiers — Personal at roughly $10/month and Professional at roughly $20/month — for teams that want the same engine without operating their own servers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb0a80b-0a80-4999-85e6-81d72d140ab9', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Automated commission calculation engine$q$, $q$Applies quota, tier, accelerator, split, and clawback logic to CRM and ERP data to compute payouts automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$No-code plan builder$q$, $q$Lets revenue operations teams configure and redesign commission plans through a visual interface without engineering tickets.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Rep-facing dashboards$q$, $q$Real-time visibility into quota attainment, projected commission, and payout history for individual sales reps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Approvals and dispute resolution$q$, $q$Formal workflows for raising, reviewing, and resolving commission discrepancies with a full audit trail.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$CRM and ERP integrations$q$, $q$Native connections to systems like Salesforce and HubSpot, plus ERP and payroll data sources, to keep commission data current.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$ASC 606 compliance module$q$, $q$An optional add-on that helps finance teams align commission accounting with ASC 606 revenue recognition requirements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Forecasting and what-if simulation$q$, $q$Tools for modeling projected commission payouts under different quota attainment or plan design scenarios.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Slack, Teams, and email alerts$q$, $q$An optional connectivity package that pushes commission and payout notifications into everyday communication tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Genuinely no-code plan configuration reduces dependence on engineering or professional services for plan changes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Strong emphasis on rep-facing transparency, which can reduce commission disputes and improve sales team trust$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Backed by well-known SaaS investors (3one4 Capital, Elevation Capital, Eight Roads Ventures) with a track record of continued funding$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Free proof-of-concept lets buyers validate real commission plans before signing a contract$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$No public pricing; buyers must go through a sales process to get a quote, which slows evaluation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Per-payee pricing plus a one-time implementation fee can make total cost harder to predict upfront$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Best suited to mid-market and enterprise companies; may be more platform than very small sales teams need$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Newer entrant compared to long-established ICM vendors like Xactly, with a shorter enterprise track record$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$How is Everstage priced?$q$, $q$Everstage uses per-payee pricing based on the number of people a company pays commissions to, with a custom quote for each customer rather than published tiers. Add-ons like Salesforce integration and ASC 606 compliance are priced separately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$What CRM systems does Everstage integrate with?$q$, $q$Everstage integrates with major CRM platforms including Salesforce and HubSpot, along with ERP, billing, and payroll systems, to pull the transactional data needed for commission calculations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Is Everstage a no-code platform?$q$, $q$Yes. Everstage's commission plan builder is designed to let revenue operations and compensation administrators configure and update plans without writing code or filing engineering requests.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Who are Everstage's main competitors?$q$, $q$Everstage competes with Xactly, Varicent, CaptivateIQ, QuotaPath, and Salesforce-owned Spiff in the incentive compensation management category.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Where is Everstage headquartered?$q$, $q$Everstage operates out of Chennai, India, with a US corporate entity headquartered in Wilmington, Delaware, reflecting its dual India-US operating structure common among India-origin B2B SaaS companies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Can I try Everstage before committing to a contract?$q$, $q$Everstage offers a free proof-of-concept engagement that lets prospective customers test their actual commission plans in the platform before signing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Automating spreadsheet-based commission tracking$q$, $q$Revenue operations teams replace manual, error-prone spreadsheet commission calculations with an automated engine connected directly to CRM and ERP data.$q$, $q$Revenue operations and sales finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Improving sales rep trust and transparency$q$, $q$Sales organizations give reps self-service dashboards showing real-time quota attainment and projected payouts to reduce disputes and improve morale.$q$, $q$Sales leaders and individual sales representatives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Managing complex, frequently changing compensation plans$q$, $q$Companies with tiered, split, or accelerator-based commission structures use the no-code plan builder to redesign plans each period without engineering involvement.$q$, $q$Sales compensation administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$Custom / Per-Payee$q$, $q$Custom (quote-based)$q$, $q$annual$q$, NULL, $q$["Commission calculation engine","No-code plan management","Rep-facing dashboards","Approvals and dispute workflows","Enterprise support with dedicated CSM","Optional add-ons: Salesforce app, Slack/Teams/Gmail alerts, ASC 606 compliance"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Everstage is a no-code incentive compensation management (ICM) platform that automates sales commission calculations, replacing manual spreadsheets with a connected system that pulls data from CRM, ERP, and payroll tools to compute payouts.$q$, $q$Founded in 2020 and based in Chennai, India with a US entity in Delaware, Everstage has raised roughly $45 million across seed, Series A, and Series B rounds to build out its platform for mid-market and enterprise revenue teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core is a calculation engine that applies commission plan logic — quotas, tiers, accelerators, splits, and clawbacks — to transactional data automatically, paired with a no-code plan builder for configuring or redesigning compensation plans without engineering help.$q$, $q$Rep-facing dashboards give salespeople real-time visibility into quota attainment and projected payouts, while an approvals and dispute-resolution workflow creates an auditable trail for finance and compliance teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Everstage does not publish standard pricing tiers; instead, it prices per payee (the number of people a company pays commissions to) with a custom quote for each customer.$q$, $q$Every contract includes the calculation engine, plan management, dashboards, approvals workflow, and enterprise support, with optional add-ons for native Salesforce integration, Slack/Teams/Gmail alerts, and an ASC 606 compliance module.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('087b7f82-9397-45ec-9b2b-8507a996af85', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Simulated live playback$q$, $q$Replays a single recorded presentation on a schedule that mimics a genuinely live event for attendees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Flexible scheduling modes$q$, $q$Recurring fixed time windows, 'just-in-time' sessions shortly after registration, or fully on-demand playback.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Simulated chat and attendee counters$q$, $q$Pre-scripted chat comments and dynamic attendee counts replay at the same timestamps each session to recreate live engagement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Timed offers and calls-to-action$q$, $q$Special offers, countdowns, and CTAs appear at specific points in the video to drive conversions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Registration page builder$q$, $q$Built-in tool for creating opt-in and confirmation pages without separate landing page software.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Email and SMS reminders$q$, $q$Automated reminder sequences bring registrants back for their chosen webinar session time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Polls and surveys$q$, $q$Interactive polls and surveys embedded in the webinar experience to boost engagement and gather audience data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Paid webinar support$q$, $q$Built-in support for charging attendees to register for premium or gated webinar sessions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Same complete feature set on every plan; no feature-gated tiers to navigate$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Mature, proven automated-webinar workflow with nearly a decade of track record among marketers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Deep direct-response marketing features (timed offers, simulated urgency, countdowns) purpose-built for sales funnels$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Bundles well with WebinarJam and Kartra for teams already in the Genesis Digital ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Flat pricing starts at $199/month, higher than several newer or freemium automated-webinar competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Interface and overall product feel are dated compared to newer entrants like Demio or Livestorm$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$No published free plan or free trial found; evaluation typically requires a paid commitment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Best suited to funnel-style sales presentations rather than general corporate or B2B live-event use cases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$What is the difference between EverWebinar and WebinarJam?$q$, $q$WebinarJam hosts genuinely live webinars, while EverWebinar replays a single recorded presentation on a schedule designed to feel live, using simulated chat and timed offers. Both are made by Genesis Digital and are often used together.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$How much does EverWebinar cost?$q$, $q$EverWebinar is $199/month with no contract, $499/year (about $42/month), or $874 for two years (about $36/month), with every plan including the full feature set.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Who makes EverWebinar?$q$, $q$EverWebinar is made by Genesis Digital, a marketing technology company founded by Andy Jenkins and Mike Filsaime, also known for WebinarJam and the all-in-one platform Kartra.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Does EverWebinar support live chat during automated webinars?$q$, $q$Yes, but the chat is simulated: pre-recorded or previously captured audience comments replay at the same timestamps each session to recreate the feel of live audience interaction.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Can I sell tickets to an EverWebinar session?$q$, $q$Yes, EverWebinar supports paid webinars, allowing marketers to charge attendees to register for premium or gated sessions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$What are the main alternatives to EverWebinar?$q$, $q$Common alternatives include WebinarJam for live events, EasyWebinar, Demio, WebinarKit, and Livestorm, several of which offer more modern interfaces or tighter integrations with broader marketing stacks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Evergreen course and info-product launches$q$, $q$Course creators record one high-converting sales webinar and let EverWebinar run it continuously on autopilot to drive enrollments without hosting live sessions repeatedly.$q$, $q$Course creators and info-product marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Agency-managed client funnels$q$, $q$Marketing agencies build and manage automated webinar funnels for clients, scaling a single proven presentation across ongoing lead generation campaigns.$q$, $q$Marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$SaaS and service sales demos at scale$q$, $q$SaaS and service businesses use a recorded product demo webinar with timed offers to qualify and convert leads without requiring live sales staff for every session.$q$, $q$SaaS and service-based businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Monthly$q$, $q$$199/month$q$, $q$monthly$q$, NULL, $q$["Unlimited attendees","All scheduling modes (recurring, just-in-time, on-demand)","Chat simulation and timed offers","Registration page builder","Email and SMS reminders"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Annual$q$, $q$$499/year (about $42/month)$q$, $q$annual$q$, NULL, $q$["Same full feature set as Monthly","Significant annual discount versus month-to-month billing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$Biennial$q$, $q$$874 every 2 years (about $36/month)$q$, $q$biennial$q$, NULL, $q$["Same full feature set as Monthly","Lowest available effective monthly rate"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$EverWebinar is automated 'evergreen' webinar software that replays a single recorded presentation on a schedule designed to feel live, complete with simulated chat, timed offers, and countdown-driven registration.$q$, $q$Built by Genesis Digital, the company behind WebinarJam and Kartra, EverWebinar has been the leading automated-webinar sibling to WebinarJam's live-event tooling since its 2016 launch.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marketers can schedule playback in three modes — fixed recurring time windows, 'just-in-time' sessions shortly after registration, or fully on-demand — while a simulated chat feed, timed calls-to-action, and dynamic attendee counters recreate the feel of a live event.$q$, $q$A built-in registration page builder plus automated email and SMS reminder sequences handle the full funnel from opt-in through the scheduled session, without requiring separate landing page software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$EverWebinar uses flat, feature-complete pricing that varies only by billing commitment: $199/month with no contract, $499/year (about $42/month), or $874 for two years (about $36/month).$q$, $q$Every plan, regardless of billing cycle, includes unlimited attendees, all scheduling modes, chat simulation, timed offers, the registration builder, and email/SMS reminders.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d87ae7b9-660c-4f9e-9f79-7e32216b89fd', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$SQL and Markdown authoring$q$, $q$Reports are written as Markdown files with embedded SQL query blocks, combining narrative text and live data in one file.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Git-native version control$q$, $q$Reports live as plain text files that can be committed, diffed, and reviewed through pull requests like any other code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Built-in visualization components$q$, $q$A library of pre-built charts, tables, and layout components that render directly from SQL query results.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Templated pages$q$, $q$A single Markdown template can generate many pages programmatically, such as one report per region, product, or customer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Universal data source support$q$, $q$Connects to warehouses and databases including Snowflake, BigQuery, Postgres, and DuckDB, among others.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Row-level and page-level security$q$, $q$Access control features that restrict which users can see which data or pages within a report.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Embeddable reports$q$, $q$Reports can be embedded in customer-facing products, not just used for internal dashboards.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$AI credits and AI features$q$, $q$Evidence Cloud plans include monthly AI credit allocations for AI-assisted report building and analysis.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Reports are version-controlled as code, enabling Git-based review, diffing, and deployment workflows familiar to engineering teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Free and open source to self-host with no artificial feature limits on the core framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Templated pages eliminate manual duplication when building many similar reports across regions, products, or customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Designed for embedding analytics into customer-facing products, not just internal dashboards$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Requires comfort writing SQL and Markdown; not accessible to non-technical business users who want pure drag-and-drop reporting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Smaller ecosystem and community than established BI incumbents like Tableau, Looker, or Power BI$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Evidence Cloud pricing is per-user, which can add up for larger analytics teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$AI features are metered via credits, adding a variable cost dimension beyond the base subscription$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$What does 'BI as code' mean for Evidence?$q$, $q$It means reports are authored as plain-text Markdown files with embedded SQL, so they can be version-controlled in Git, reviewed via pull requests, and deployed like any other code, instead of being stored as opaque objects inside a proprietary BI tool.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Is Evidence free to use?$q$, $q$Yes, the core Evidence framework is free and open source to self-host. Evidence Cloud, a paid managed hosting option, starts at $15 per user per month for the Team plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$What data sources does Evidence support?$q$, $q$Evidence connects to common data warehouses and databases including Snowflake, BigQuery, Postgres, DuckDB, and many others through its data source connectors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Who is Evidence best suited for?$q$, $q$Evidence is best suited for data engineers, analytics engineers, and technical analysts already working in a code-first, Git-based data stack, often alongside tools like dbt.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$How is Evidence different from Metabase or Tableau?$q$, $q$Metabase and Tableau are primarily GUI-driven tools for building dashboards through point-and-click interfaces. Evidence is authored entirely in SQL and Markdown, with reports stored as version-controlled code rather than objects inside the tool itself.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Can Evidence reports be embedded in other products?$q$, $q$Yes, embeddable reports are a core feature, particularly on the Evidence Cloud Enterprise plan, which supports white-labeling and embedding analytics into customer-facing applications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Internal analytics for lean data teams$q$, $q$A small analytics engineering team builds and maintains a full internal reporting suite using the same Git workflow they already use for data pipeline code.$q$, $q$Data and analytics engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Customer-facing embedded analytics$q$, $q$A SaaS company embeds Evidence-built reports directly into its product to give customers self-service analytics without building a custom dashboard from scratch.$q$, $q$SaaS product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Automated multi-entity reporting$q$, $q$An organization uses templated pages to automatically generate a separate performance report for every region, store, or account from a single report definition.$q$, $q$Operations and business analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full framework access","Self-hosted deployment","Unlimited projects and data sources","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Team$q$, $q$$15/user/month$q$, $q$monthly$q$, NULL, $q$["Unlimited users","Row-level and page-level access control","Log In With Google","1,000 AI credits/user/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Pro$q$, $q$$25/user/month$q$, $q$monthly$q$, NULL, $q$["Everything in Team","Single sign-on (SSO)","Directory sync (SCIM)","Private Slack support","3,000 AI credits/user/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$Enterprise$q$, $q$Custom$q$, $q$annual (quote-based)$q$, NULL, $q$["Everything in Pro","White labeling and embedded reports","Multi-region support","Dedicated support","Custom AI credit volume"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Evidence is an open source 'BI-as-code' framework that lets data teams build reports, dashboards, and embedded analytics using SQL embedded inside Markdown files, all version-controlled in Git rather than stored inside a proprietary BI tool.$q$, $q$Founded in 2021 by Sean Hughes and Adam McAskill through Y Combinator, Evidence is free and open source to self-host, with an optional paid Evidence Cloud offering for managed hosting and enterprise features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Developers write SQL queries directly inside Markdown files; Evidence executes those queries against connected data sources and renders the results using a built-in library of chart, table, and layout components.$q$, $q$Templated pages let a single Markdown definition programmatically generate many similar reports — for example, one report per region or customer — driven entirely by the underlying data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Evidence's core framework is free and open source for self-hosting on your own infrastructure and data sources, with no license fee.$q$, $q$Evidence Cloud offers managed hosting across three paid tiers: Team at $15/user/month, Pro at $25/user/month, and a custom-priced Enterprise tier with white-labeling, embedding, and advanced security features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
