INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5512df11-bacf-4edc-8977-91af599645ef', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$100+ built-in evaluation metrics$q$, $q$A large library of pre-built statistical tests and metrics covering data drift, model performance, and data quality.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$LLM and RAG evaluation$q$, $q$Metrics for evaluating generative AI systems, including relevance, correctness, toxicity, and hallucination detection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Data drift detection$q$, $q$Automated comparison of reference and current datasets to flag distribution shifts before they degrade model performance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Interactive reports and test suites$q$, $q$Generates HTML reports, JSON output, or structured pass/fail test results for use in notebooks or pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Synthetic data generation$q$, $q$Creates synthetic evaluation datasets for testing LLM applications when labeled test data is scarce.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$CI/CD and orchestration integration$q$, $q$Runs as a Python library inside Airflow, Prefect, or CI/CD pipelines to codify model and data quality checks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Evidently Cloud dashboards$q$, $q$A hosted platform for tracking model and prompt performance trends over time with team collaboration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Alerting on metric thresholds$q$, $q$Configurable alerts that notify teams when monitored metrics breach defined thresholds.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Core framework is fully open source and free under Apache 2.0, with no artificial feature limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Very large, well-adopted library (20+ million downloads) covering both classical ML and modern LLM evaluation needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Code-first design integrates naturally into existing data science and MLOps workflows rather than requiring a separate GUI tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Actively expanding metric coverage to keep pace with LLM and RAG evaluation, a fast-moving area of need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$No published self-serve pricing for Evidently Cloud; enterprise plans require a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Being code-first, it is less accessible to non-technical stakeholders who want a pure point-and-click dashboard$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Smaller company and funding scale than some closed-source competitors like Arize AI or Fiddler AI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Best value requires engineering effort to integrate into pipelines rather than a plug-and-play setup$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Is Evidently AI free to use?$q$, $q$Yes, the core Evidently framework is fully open source and free under an Apache 2.0 license. A commercial Evidently Cloud platform is also available for teams that want hosted dashboards and collaboration features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Does Evidently AI support LLM evaluation?$q$, $q$Yes, Evidently has expanded beyond classical ML monitoring to include LLM and RAG-specific evaluation metrics such as relevance, correctness, toxicity, and hallucination detection.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$How is Evidently AI typically used?$q$, $q$It's installed as a Python library and used inside notebooks, orchestration pipelines, or CI/CD systems to run drift detection, performance evaluation, and data quality checks on models and data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Who founded Evidently AI?$q$, $q$Evidently AI was founded in 2020 by Emeli Dral and Elena Samuylova and is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$What are the main alternatives to Evidently AI?$q$, $q$Competitors in the ML and LLM observability space include Arize AI, WhyLabs, Fiddler AI, and Galileo, several of which have also expanded into LLM evaluation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$How much does Evidently Cloud cost?$q$, $q$Evidently AI does not publish self-serve pricing for its Cloud platform; interested teams need to contact sales for a custom quote.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Production ML model monitoring$q$, $q$ML engineering teams use Evidently to detect data drift and performance degradation in models running in production before they silently fail.$q$, $q$ML engineers and MLOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$LLM application evaluation before launch$q$, $q$Teams building RAG or LLM-powered features use Evidently's metrics to test for hallucination, relevance, and correctness before shipping to users.$q$, $q$AI and product engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$CI/CD-integrated model quality gates$q$, $q$Data teams codify model and data quality checks as automated tests that run in their CI/CD pipeline alongside regular software tests.$q$, $q$Data engineering and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["100+ evaluation metrics","Data drift and quality checks","LLM and RAG evaluation metrics","Full library access under Apache 2.0"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$Evidently Cloud$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Hosted dashboards","Team collaboration","Alerting on metric thresholds","Trend tracking over time"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Evidently AI is an open source Python framework for evaluating, testing, and monitoring machine learning models, data pipelines, and LLM applications, built around a library of more than 100 pre-built evaluation metrics.$q$, $q$Founded in 2020 by Emeli Dral and Elena Samuylova and headquartered in San Francisco, the company also offers a commercial hosted platform, Evidently Cloud, for teams that want shared dashboards, alerting, and collaboration on top of the open source engine.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The library covers data drift detection, model performance evaluation, and data quality checks for traditional ML, plus LLM-specific evaluation criteria like relevance, correctness, toxicity, and hallucination detection for generative AI systems.$q$, $q$Because it ships as a Python library, Evidently integrates directly into existing workflows such as Jupyter notebooks, orchestration pipelines, and CI/CD systems, letting teams codify model and data quality checks the same way they codify unit tests.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Evidently framework is fully free and open source under an Apache 2.0 license, with no feature gating on the evaluation and monitoring engine itself.$q$, $q$Evidently Cloud, the hosted dashboard and collaboration layer, is available through a sales conversation rather than published self-serve pricing tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77429280-36af-46ef-b496-25b4c65c2176', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$AI contract data extraction$q$, $q$Extracts more than 230 data points from contracts automatically, trained on a corpus of roughly 11 million contracts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Intelligent contract repository$q$, $q$Searchable repository organized by clause type, renewal date, counterparty, or any extracted data point.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Obligation and renewal tracking$q$, $q$Monitors contractual deadlines and triggers automated notifications ahead of renewal or termination windows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Approval workflow automation$q$, $q$Automates drafting, redlining, and internal sign-off processes for contract review cycles.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Risk scoring and analytics$q$, $q$Dashboards that surface approval bottlenecks and flag contracts with unusual or high-risk terms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$E-signature and CRM integrations$q$, $q$Connects to tools like DocuSign and Salesforce to fit into existing contract execution and sales workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Workday platform integration$q$, $q$Increasingly integrated natively into Workday's HR and finance modules as Workday Contract Intelligence.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Compliance audit trail$q$, $q$Provides an auditable record of contractual obligations and risk exposure for compliance teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$AI extraction models trained on a very large proprietary contract dataset, giving strong out-of-the-box accuracy on standard clauses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Serves multiple functions (legal, procurement, finance, compliance) from a single contract data source$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Now backed by Workday's scale, engineering resources, and enterprise customer base following the 2024 acquisition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Well-capitalized history ($155.6M raised) reflects sustained investment in its AI research and product depth$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$No public self-serve pricing; enterprise sales cycle required for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Brand and product roadmap are being absorbed into Workday, creating uncertainty for customers who wanted a standalone best-of-breed CLM vendor$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Best fit is likely narrowing toward existing or prospective Workday customers rather than organizations using other HR/finance platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Transition period following an acquisition can mean slower feature releases as products are integrated$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Is Evisort still an independent company?$q$, $q$No. Workday acquired Evisort in a deal announced in September 2024, and its technology is now being integrated into and rebranded within Workday's platform as Workday Contract Intelligence and Workday CLM.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$What does Evisort's AI actually do?$q$, $q$Evisort's AI model, trained on roughly 11 million contracts, automatically extracts more than 230 data points from any uploaded contract, such as parties, dates, renewal terms, and key clauses, without manual tagging.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$How much does Evisort cost?$q$, $q$Evisort has always used custom, quote-based enterprise pricing rather than published tiers, and since the Workday acquisition its capabilities are increasingly sold as part of Workday's broader platform licensing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Who founded Evisort?$q$, $q$Evisort was founded in 2016 by Jerry Ting, Jake Sussman, and Amine Anoun, a team with roots in Harvard Law School and MIT, incubated in part through Harvard Innovation Labs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$What are the main alternatives to Evisort?$q$, $q$Competitors in the AI-powered contract lifecycle management space include Ironclad, ContractPodAi, Icertis, SirionLabs, and Agiloft.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Who should consider Evisort/Workday Contract Intelligence?$q$, $q$It is best suited for organizations already using or evaluating Workday for HR and finance that want native AI-powered contract intelligence, as well as legal, procurement, and finance teams managing large contract portfolios.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Legal contract review acceleration$q$, $q$Legal teams use AI extraction to reduce manual data entry and speed up review of incoming and existing contracts.$q$, $q$Corporate legal and contracts teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Procurement obligation and renewal tracking$q$, $q$Procurement teams track supplier obligations and use extracted renewal data to identify renegotiation opportunities before contracts auto-renew.$q$, $q$Procurement and vendor management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Finance visibility into contractual liabilities$q$, $q$Finance leaders use structured contract data to gain visibility into revenue recognition timing and upcoming financial commitments.$q$, $q$Finance and revenue operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$Custom / Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual (quote-based)$q$, NULL, $q$["AI contract data extraction","Intelligent contract repository","Obligation and renewal tracking","Approval workflow automation","Risk scoring and analytics","Increasingly bundled with Workday HR/finance licensing"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Evisort is an AI-powered contract lifecycle management platform that automatically extracts, organizes, and analyzes contract data, helping legal, procurement, and finance teams manage contracts from drafting through renewal and compliance.$q$, $q$Founded in 2016 by a Harvard Law and MIT-affiliated team, Evisort was acquired by Workday in a deal announced in September 2024, and its technology is now integrated into and rebranded as Workday Contract Intelligence and Workday CLM.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's AI model, trained on roughly 11 million contracts, extracts more than 230 data points from any uploaded contract — parties, dates, renewal terms, and key clauses — without manual tagging, claiming above 90 percent accuracy on standard clauses.$q$, $q$Beyond extraction, the platform provides an intelligent, searchable contract repository, automated obligation and renewal tracking, approval workflow automation, and risk-scoring dashboards for legal, procurement, and finance teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Evisort has always used custom, quote-based enterprise pricing rather than published self-serve tiers, reflecting its positioning as an enterprise-grade CLM platform.$q$, $q$Since the September 2024 Workday acquisition, its capabilities are increasingly sold as part of Workday's broader HR and finance platform licensing rather than as a fully standalone product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57b9a346-5643-4807-89c0-802cddc8a87c', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Hand-drawn sketch rendering$q$, $q$A distinctive sketchy visual style for shapes, arrows, and text that gives diagrams an informal, hand-drawn look.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Infinite canvas$q$, $q$An unbounded drawing surface for sketching diagrams of any size without running out of space.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Real-time multiplayer collaboration$q$, $q$Unlimited collaborators can draw together on the same scene simultaneously, even on the free tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$End-to-end encrypted sharing$q$, $q$Scenes shared via collaboration links are encrypted locally in the browser so Excalidraw's servers cannot read the content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Export to PNG, SVG, and clipboard$q$, $q$One-click export of any diagram to common image formats or directly to the clipboard for pasting elsewhere.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Embeddable via npm package$q$, $q$The open source editor component can be embedded directly into third-party products and internal tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Excalidraw+ cloud workspace$q$, $q$Persistent cloud storage, unlimited scenes and folders, and team access management on the paid tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$AI-assisted diagramming$q$, $q$Extended AI features on Excalidraw+ that help generate or assist with diagram creation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Core editor is completely free with no feature restrictions, including unlimited real-time collaborators$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Open source and embeddable, letting developers integrate the editor directly into their own products$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Distinctive hand-drawn aesthetic is fast to use and widely recognized across technical documentation and blogs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Bootstrapped and sustainably run without venture funding pressure to monetize aggressively$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Free tier stores scenes locally in the browser only; persistent cloud storage requires an Excalidraw+ subscription$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Feature set is intentionally narrower than full-featured whiteboard suites like Miro or FigJam$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Less suited to precise, structured diagramming compared to tools like Lucidchart or Visio$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Small maintaining team relative to its large user base could limit the pace of major new feature development$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Is Excalidraw completely free?$q$, $q$Yes, the core Excalidraw editor is free forever with no restrictions on drawing tools, shapes, or real-time collaborators. Excalidraw+ is an optional paid tier for cloud storage and team features, priced at $6 per user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Who created Excalidraw?$q$, $q$Excalidraw was created by Christopher Chedeau, a Meta software engineer known as 'vjeux' and co-creator of React Native and Prettier, who launched it on January 1, 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Can Excalidraw be embedded into other apps?$q$, $q$Yes, because Excalidraw is open source under the MIT license, its editor component is published as an npm package that developers can embed directly into their own products and internal tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Is Excalidraw venture-funded?$q$, $q$No. Excalidraw has zero recorded funding rounds and is sustained by revenue from Excalidraw+ subscriptions rather than venture capital.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$What is included in Excalidraw+?$q$, $q$Excalidraw+ adds persistent cloud storage, unlimited scenes and folders, access management and sharing permissions, voice and video collaboration, presentation mode, extended AI features, and team management tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$What are the best alternatives to Excalidraw?$q$, $q$Common alternatives include tldraw (a similarly open source sketching canvas), Miro and FigJam for broader team whiteboarding, and structured diagramming tools like Lucidchart, draw.io (diagrams.net), and Microsoft Visio.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$System architecture and technical diagrams$q$, $q$Software engineers sketch system architecture, data flow, and infrastructure diagrams quickly, often embedding the output directly in documentation.$q$, $q$Software engineers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Remote whiteboarding and pairing$q$, $q$Distributed teams use Excalidraw's real-time collaboration for whiteboarding during video calls and remote pair-programming sessions.$q$, $q$Remote and distributed teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Quick wireframes and product sketches$q$, $q$Product managers and designers rough out UI wireframes and flow diagrams fast without the overhead of a full design tool.$q$, $q$Product managers and designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full editor functionality","Infinite canvas, one scene","Unlimited real-time collaborators","Export to PNG, SVG, or clipboard","End-to-end encrypted local libraries"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$Excalidraw+$q$, $q$$6/user/month (annual discount available)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Free","Unlimited scenes and folders","Persistent cloud storage","Access management and sharing permissions","Voice/video collaboration and presentation mode","Extended AI features and team management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Excalidraw is a free, open source virtual whiteboard for sketching diagrams, flowcharts, and wireframes with a distinctive hand-drawn visual style, built as a browser-based canvas application in React and TypeScript.$q$, $q$Created by Christopher Chedeau (co-creator of React Native and Prettier) and launched on January 1, 2020, Excalidraw has grown into one of the most widely starred open source design tools on GitHub while remaining entirely unfunded and bootstrapped.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free editor includes an infinite canvas, all core drawing and shape tools, unlimited real-time collaborators, and export to PNG, SVG, or clipboard, with end-to-end encrypted sharing so Excalidraw's own servers cannot read shared scene content.$q$, $q$The open source component is also embeddable into other products via its npm package, which is why the hand-drawn Excalidraw style shows up widely across technical blogs, documentation, and third-party tools beyond the hosted excalidraw.com site.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Excalidraw editor is free forever with no feature restrictions on drawing, collaboration, or export.$q$, $q$Excalidraw+, priced at $6 per user per month (with an annual discount), adds persistent cloud storage, unlimited scenes and folders, access management, voice/video collaboration, presentation mode, and extended AI features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ca5270f-e111-4975-805d-895270a05cb1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
